function randomToken(len = 8) {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  let out = '';
  for (let i = 0; i < len; i++) {
    out += chars[Math.floor(Math.random() * chars.length)];
  }
  return out;
}

// 현재 시각
const now = new Date();
const yyyy = now.getFullYear();
const mm = ('0' + (now.getMonth() + 1)).slice(-2);
const dd = ('0' + now.getDate()).slice(-2);
const hh = ('0' + now.getHours()).slice(-2);
const min = ('0' + now.getMinutes()).slice(-2);
const ss = ('0' + now.getSeconds()).slice(-2);

// YYMMDDhhmmss 타임스탬프
const timestamp = `${String(yyyy).slice(-2)}${mm}${dd}${hh}${min}${ss}`;
const token = randomToken(8);

// 사용자가 업로드한 원본 파일명 (개행 제거)
const originalName = $binary.file?.fileName?.replace(/[\n\r]/g, '') || 'unknown';

// 원본 파일명에서 확장자 추출 (있으면 유지, 없으면 빈 문자열)
let ext = '';
const extMatch = originalName.match(/\.[0-9A-Za-z]+$/);
if (extMatch) {
  ext = extMatch[0]; // 예: ".jpeg"
}

// 최종 저장 이름: YYMMDDhhmmss_random + 확장자(있으면)
const saveName = `${timestamp}_${token}${ext}`;

// 최종 폴더 (/data/files/YYYY/MM)
const folder = `/data/files/${yyyy}/${mm}`;

// 최종 경로
const destPath = `${folder}/${saveName}`;

return [{
  json: {
    tmpPath: $json.filePath,  // 임시 저장 파일 경로
    folder,                   // 최종 폴더
    destPath,                 // 최종 경로
    saveName,                 // 최종 파일명
    originalName              // 원본 업로드 파일명
  }
}];

